import{_ as e,O as p,H as o,f as l,b as s,j as n,k as i,i as r}from"./chunks/framework.Pt2pSV98.js";const w=JSON.parse('{"title":"Few-Shot / Zero-Shot","description":"理解 Zero-Shot 和 Few-Shot 的区别，学会用示例引导 AI 输出","frontmatter":{"title":"Few-Shot / Zero-Shot","description":"理解 Zero-Shot 和 Few-Shot 的区别，学会用示例引导 AI 输出","difficulty":"beginner"},"headers":[],"relativePath":"prompts/few-shot.md","filePath":"prompts/few-shot.md"}'),h={name:"prompts/few-shot.md"},d={id:"few-shot-zero-shot",tabindex:"-1"};function c(u,a,g,b,f,m){const t=p("DifficultyBadge");return o(),l("div",null,[s("h1",d,[a[0]||(a[0]=n("Few-Shot / Zero-Shot ",-1)),i(t,{level:"beginner"}),a[1]||(a[1]=n()),a[2]||(a[2]=s("a",{class:"header-anchor",href:"#few-shot-zero-shot","aria-label":'Permalink to "Few-Shot / Zero-Shot <DifficultyBadge level="beginner" />"'},"​",-1))]),a[3]||(a[3]=r(`<p><strong>Zero-Shot</strong> 和 <strong>Few-Shot</strong> 是提示词工程中最基础的两个概念，它们描述的是你在 Prompt 中<strong>是否提供示例</strong>。</p><hr><h2 id="zero-shot-不给示例-直接提问" tabindex="-1">Zero-Shot：不给示例，直接提问 <a class="header-anchor" href="#zero-shot-不给示例-直接提问" aria-label="Permalink to &quot;Zero-Shot：不给示例，直接提问&quot;">​</a></h2><p>Zero-Shot 意为&quot;零示例&quot;。你直接问问题，不给任何示范，AI 凭自身知识回答。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把以下句子翻译成英文：今天天气真好。</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请判断这句话的情感倾向是正面还是负面：&quot;这个产品太难用了，我要退款！&quot;</span></span></code></pre></div><p><strong>适用场景</strong>：任务简单明确、AI 有充足训练知识、你不需要特定风格或格式。</p><p><strong>局限性</strong>：对于格式要求高或风格特殊的任务，Zero-Shot 的效果往往不够好。</p><hr><h2 id="few-shot-先给示例-再提问题" tabindex="-1">Few-Shot：先给示例，再提问题 <a class="header-anchor" href="#few-shot-先给示例-再提问题" aria-label="Permalink to &quot;Few-Shot：先给示例，再提问题&quot;">​</a></h2><p>Few-Shot 意为&quot;少量示例&quot;。你在 Prompt 中先展示 2-3 个<strong>输入→输出</strong>示例，再让 AI 处理你的实际输入。</p><h3 id="示例-文本分类" tabindex="-1">示例：文本分类 <a class="header-anchor" href="#示例-文本分类" aria-label="Permalink to &quot;示例：文本分类&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请判断以下句子的情感倾向（正面/负面/中性）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例 1：</span></span>
<span class="line"><span>输入：物流太慢了，等了一周才到！</span></span>
<span class="line"><span>输出：负面</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例 2：</span></span>
<span class="line"><span>输入：质量不错，性价比很高，会回购。</span></span>
<span class="line"><span>输出：正面</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例 3：</span></span>
<span class="line"><span>输入：收到了，还没用，暂时不做评价。</span></span>
<span class="line"><span>输出：中性</span></span>
<span class="line"><span></span></span>
<span class="line"><span>现在请判断：</span></span>
<span class="line"><span>输入：包装完好，但颜色和图片差太多了。</span></span>
<span class="line"><span>输出：</span></span></code></pre></div><p>通过 3 个示例，AI 不仅学会了分类任务，还学会了你的输出格式（只写&quot;正面/负面/中性&quot;）。</p><h3 id="示例-风格模仿" tabindex="-1">示例：风格模仿 <a class="header-anchor" href="#示例-风格模仿" aria-label="Permalink to &quot;示例：风格模仿&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请用以下风格回复客户投诉：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例 1：</span></span>
<span class="line"><span>客户：你们发货太慢了！</span></span>
<span class="line"><span>回复：非常抱歉给您带来不便！我已查询您的订单 #12345，目前正在配送中，预计明天送达。为表歉意，已为您申请一张 20 元优惠券，请注意查收。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例 2：</span></span>
<span class="line"><span>客户：收到的商品有划痕！</span></span>
<span class="line"><span>回复：非常抱歉！请您拍照发送给我们，我立刻为您安排换货或退款，您选择哪种方式都可以。您的满意对我们很重要。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>现在请回复：</span></span>
<span class="line"><span>客户：你们的 App 老是闪退，根本用不了！</span></span>
<span class="line"><span>回复：</span></span></code></pre></div><hr><h2 id="对比效果表" tabindex="-1">对比效果表 <a class="header-anchor" href="#对比效果表" aria-label="Permalink to &quot;对比效果表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Zero-Shot</th><th>Few-Shot</th></tr></thead><tbody><tr><td>Prompt 长度</td><td>短</td><td>较长</td></tr><tr><td>输出格式控制</td><td>弱</td><td>强</td></tr><tr><td>风格一致性</td><td>不稳定</td><td>稳定</td></tr><tr><td>适用任务</td><td>简单任务</td><td>复杂/格式要求高的任务</td></tr><tr><td>示例数量</td><td>0</td><td>通常 2-5 个</td></tr></tbody></table><hr><h2 id="few-shot-最佳实践" tabindex="-1">Few-Shot 最佳实践 <a class="header-anchor" href="#few-shot-最佳实践" aria-label="Permalink to &quot;Few-Shot 最佳实践&quot;">​</a></h2><ol><li><strong>示例要典型</strong> — 选择有代表性的案例，覆盖不同情况</li><li><strong>格式要一致</strong> — 所有示例使用相同的输入→输出结构</li><li><strong>数量要适中</strong> — 2-3 个通常足够，超过 5 个边际收益递减</li><li><strong>先易后难</strong> — 示例从简单到复杂排列</li><li><strong>最后放实际输入</strong> — 把你要处理的内容放在所有示例之后</li></ol><hr><h2 id="进阶阅读" tabindex="-1">进阶阅读 <a class="header-anchor" href="#进阶阅读" aria-label="Permalink to &quot;进阶阅读&quot;">​</a></h2><ul><li><a href="./principles.html">清晰指令五原则</a> — Few-Shot 是&quot;给出示例&quot;原则的具体实践</li><li><a href="./writing.html">写作类模板</a> — 很多模板使用了 Few-Shot 技巧</li></ul>`,25))])}const v=e(h,[["render",c]]);export{w as __pageData,v as default};
